  position: absolute;
  right: 0; left: auto; top: 0;
  color: #2c3e50;
  font-weight: 600;
  text-align: right;
  width: 100%;
}

/* ================================
   2) Colores de íconos Editar/Eliminar
   (SVG embebidos como )
================================ */
[selector="list-record"] td[aria-colindex="4"] .actions [title="Editar"] img{
  transition: filter .15s ease, transform .12s ease;
  filter: invert(17%) sepia(22%) saturate(2557%) hue-rotate(171deg) brightness(92%) contrast(92%);
}
[selector="list-record"] td[aria-colindex="4"] .actions [title="Editar"]:hover img{
  filter: invert(13%) sepia(27%) saturate(2412%) hue-rotate(173deg) brightness(80%) contrast(95%);
  transform: translateY(-1px);
}

/* ELIMINAR -> Rojo (#dc2626) */
[selector="list-record"] td[aria-colindex="4"] .actions [title="Eliminar"] img{
  transition: filter .15s ease, transform .12s ease;
  filter: invert(14%) sepia(90%) saturate(6268%) hue-rotate(356deg) brightness(90%) contrast(104%);
}
[selector="list-record"] td[aria-colindex="4"] .actions [title="Eliminar"]:hover img{
  filter: invert(11%) sepia(93%) saturate(5530%) hue-rotate(355deg) brightness(70%) contrast(110%);
  transform: translateY(-1px);
}

/* Accesibilidad: micro-resalte al enfocar con teclado */
[selector="list-record"] td[aria-colindex="4"] .actions .btn:focus img{
  outline: none;
  filter: drop-shadow(0 0 0.25rem rgba(15,76,129,.35));
}

/* ================================
   3) POPOVER dinámico anclado al grupo de acciones
   (reemplaza tu margin-top fijo)
================================ */

/* Asegura que el popover pueda “salirse” visualmente de la celda */
[selector="list-record"] td[aria-colindex="4"]{
  overflow: visible; /* para que no lo recorte la celda */
}

/* El contenedor de botones será el ancla de posicionamiento */
[selector="list-record"] td[aria-colindex="4"] .actions{
  position: relative; /* ancla */
  z-index: 1;
}

/* Popover colocado respecto a .actions, sin offsets mágicos */
[selector="list-record"] td[aria-colindex="4"] .actions .popover-content{
  position: absolute;
  right: 0;
  /* —> mostrar ARRIBA de los botones (no abajo) */
  top: auto;
  bottom: calc(100% + 8px);
  z-index: 2000;

  margin-top: 0 !important;
  background: #fff;
  border: 1px solid #e5e7eb;
  border-radius: 8px;
  padding: 10px 12px;
  box-shadow: 0 10px 24px rgba(0,0,0,.12);
  width: max-content;
  max-width: clamp(220px, 40vw, 320px);
}

/* Flechita del popover (opcional) */
[selector="list-record"] td[aria-colindex="4"] .actions .popover-content::before{
  content: "";
  position: absolute;
  bottom: -6px;
  right: 14px;
  border-width: 6px;
  border-style: solid;
  border-color: #fff transparent transparent transparent;
  filter: drop-shadow(0 1px 0 #e5e7eb);
}

/* Variante para mostrarlo hacia arriba cuando no hay espacio abajo */
[selector="list-record"] td[aria-colindex="4"] .actions .popover-content.popover--top{
  top: auto;
  bottom: calc(100% + 8px);
}
[selector="list-record"] td[aria-colindex="4"] .actions .popover-content.popover--top::before{
  top: auto;
  bottom: -6px;
  border-color: #fff transparent transparent transparent;
  filter: drop-shadow(0 1px 0 #e5e7eb);
}

/* Limitar el alcance a tu tabla */
[selector="list-record"] .actions .popover-content p,
[selector="list-record"] .actions .popover-content .btn {
  position: relative;
  /* Oculta el texto original sin romper layout */
  color: transparent !important;
  font-size: 0 !important;
}

/* Texto del mensaje */
[selector="list-record"] .actions .popover-content p::after {
  content: "¿Confirmas que deseas eliminar este registro?";
  font-size: 0.95rem;
  color: #111827;
  line-height: 1.35;
  display: block;
}

/* Botón CANCEL → Cancelar */
[selector="list-record"] .actions .popover-content .btn.btn-light::after {
  content: "Cancelar";
  font-size: 0.875rem;
  color: #374151;
}

/* Botón DELETE → Eliminar */
[selector="list-record"] .actions .popover-content .btn.btn-danger::after {
  content: "Eliminar";
  font-size: 0.875rem;
  color: #fff;
}

/* Mantener clics y foco normal (el pseudo no captura eventos) */
[selector="list-record"] .actions .popover-content p::after,
[selector="list-record"] .actions .popover-content .btn::after {
  pointer-events: none;
